46	// The Metric Catalog — the user-facing surface of the semantic layer. Tracked =
47	// catalogued metrics (the moat); Candidates = operationalized cards eligible to
48	// be promoted. See docs/backlog/object-model-and-catalog.md.
49	export default function CatalogPage() {
50	  const client = useClerkSupabase();
51	  const navigate = useNavigate();
52	
53	  const [tab, setTab] = useState('tracked');
54	  const [tracked, setTracked] = useState<TrackedMetric[]>([]);
55	  const [candidates, setCandidates] = useState<CandidateCard[]>([]);
56	  const [busy, setBusy] = useState(false);
57	  const [error, setError] = useState<string | null>(null);
58	  const [search, setSearch] = useState('');
59	  const [usage, setUsage] = useState<Record<string, MetricUsage[]>>({});
60	  const [expandedId, setExpandedId] = useState<string | null>(null);
61	  const [editingId, setEditingId] = useState<string | null>(null);
62	  const [draft, setDraft] = useState({
63	    name: '',
64	    unit: '',
65	    owner_label: '',
66	    formula: '',
67	  });
68	
69	  const load = async () => {
70	    if (!client) return;
71	    setBusy(true);
72	    setError(null);
73	    try {
74	      const [t, c] = await Promise.all([
75	        listTrackedMetrics(client),
76	        listCandidateCards(client),
77	      ]);
78	      setTracked(t);
79	      setCandidates(c);
80	    } catch (e) {
81	      setError(e instanceof Error ? e.message : 'Failed to load the catalog.');
82	    } finally {
83	      setBusy(false);
84	    }
85	  };
86	
87	  useEffect(() => {
88	    if (client) load();
89	    // eslint-disable-next-line react-hooks/exhaustive-deps
90	  }, [client]);
91	
92	  const promote = async (card: CandidateCard) => {
93	    if (!client) return;
94	    setError(null);
