                      variant="ghost"
                      size="sm"
                      onClick={() => removeProperty(p.id)}
                      title="Remove property"
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

