1	// Semantic layer — the workspace Metric Catalog. A Tracked Metric is the shared
2	// definition of a real, sourced metric (see docs/backlog/object-model-and-catalog.md).
3	// Born when an operationalized card (Source Node -> Metric Card with real data) is
4	// explicitly catalogued; other canvases reference it via metric_cards.tracked_metric_id.
5	// Owner-scoped for now (created_by); re-scoped to the Clerk-org workspace later.
6	
7	import type { SupabaseClient } from '@supabase/supabase-js';
8	import type { MetricValue } from '@/shared/types';
9	import { supabase } from '../client';
10	import type { Database } from '../types';
11	
12	type Client = SupabaseClient<Database>;
13	
14	// ── B.2 value store ─────────────────────────────────────────────────────────
15	// The shared series for a Tracked Metric (one row per period). Cards that
16	// reference the metric read this single history, so values are consistent
17	// everywhere.
18	
19	/** Read a Tracked Metric's shared series (ordered by period). */
20	export async function getMetricValues(
21	  trackedMetricId: string,
22	  client?: Client
23	): Promise<MetricValue[]> {
24	  const c = client || supabase();
25	  const { data, error } = await c
26	    .from('metric_values')
27	    .select('period, value, change_percent, trend')
28	    .eq('tracked_metric_id', trackedMetricId)
29	    .order('period', { ascending: true });
30	  if (error) throw new Error(error.message);
31	  return (data ?? []).map((r) => ({
32	    period: r.period,
33	    value: r.value,
34	    change_percent: r.change_percent ?? 0,
35	    trend: (r.trend as MetricValue['trend']) ?? 'neutral',
36	  }));
37	}
38	
39	/** Batch-read shared series for many Tracked Metrics, grouped by metric id. */
40	export async function getMetricValuesByMetricIds(
41	  ids: string[],
42	  client?: Client
43	): Promise<Record<string, MetricValue[]>> {
44	  if (!ids.length) return {};
45	  const c = client || supabase();
46	  const { data, error } = await c
47	    .from('metric_values')
48	    .select('tracked_metric_id, period, value, change_percent, trend')
49	    .in('tracked_metric_id', ids)
50	    .order('period', { ascending: true });
51	  if (error) throw new Error(error.message);
52	  const out: Record<string, MetricValue[]> = {};
53	  for (const r of data ?? []) {
54	    (out[r.tracked_metric_id] ??= []).push({
55	      period: r.period,
56	      value: r.value,
57	      change_percent: r.change_percent ?? 0,
58	      trend: (r.trend as MetricValue['trend']) ?? 'neutral',
59	    });
60	  }
61	  return out;
62	}
63	
64	/** Upsert a Tracked Metric's series (one row per period). */
65	export async function writeMetricValues(
66	  trackedMetricId: string,
67	  series: MetricValue[],
68	  source?: string,
69	  client?: Client
70	): Promise<void> {
71	  if (!series.length) return;
72	  const c = client || supabase();
73	  const rows = series.map((p) => ({
74	    tracked_metric_id: trackedMetricId,
75	    period: p.period,
76	    value: p.value,
77	    change_percent: p.change_percent,
78	    trend: p.trend,
79	    source: source ?? null,
80	    updated_at: new Date().toISOString(),
81	  }));
82	  const { error } = await c
83	    .from('metric_values')
84	    .upsert(rows, { onConflict: 'tracked_metric_id,period' });
85	  if (error) throw new Error(error.message);
86	}
87	
88	/**
89	 * Sync a card's series into the shared store IF the card is catalogued. No-op
90	 * for uncatalogued cards. Call after any value change to a tracked card.
91	 */
92	export async function syncCardValuesToCatalog(
93	  trackedMetricId: string | null | undefined,
94	  series: MetricValue[] | undefined,
