'use client';

import { resolveChartSeries } from '@/features/canvas/utils/chartData';
import { useCanvasStore } from '@/lib/stores';
import { Button } from '@/shared/components/ui/button';
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from '@/shared/components/ui/card';
import { MetricChart, type ChartType } from '@/shared/components/charts/MetricChart';
import type { MetricCard } from '@/shared/types';
import { cn } from '@/shared/utils';
import { type NodeProps } from '@xyflow/react';
import { FourSideHandles } from './FourSideHandles';
import {
  AreaChartIcon,
  BarChart3,
  GripVertical,
  LineChartIcon,
  PieChartIcon,
  Settings2,
} from 'lucide-react';
import { memo, useMemo, useState } from 'react';
import { ChartNodeSettings } from './chart-node-settings';

export type { ChartType };

export interface ChartNodeData {
  chartType?: ChartType;
  title?: string;
  seriesCardIds?: string[];
  showLegend?: boolean;
}

const TYPE_ICON: Record<ChartType, React.ComponentType<{ className?: string }>> =
  {
    line: LineChartIcon,
    area: AreaChartIcon,
    bar: BarChart3,
    pie: PieChartIcon,
  };

const ChartNodeInner = memo(({ id, data, selected }: NodeProps) => {
  const nodeData = (data || {}) as ChartNodeData;
  const chartType: ChartType = nodeData.chartType ?? 'area';
  const title = nodeData.title ?? 'Chart';
  const showLegend = nodeData.showLegend ?? true;
  const seriesCardIds = useMemo(
    () => nodeData.seriesCardIds ?? [],
    [nodeData.seriesCardIds]
  );

  const [settingsOpen, setSettingsOpen] = useState(false);

  // Live metric cards — re-renders when an operator sim updates a plotted card.
  const cards = useCanvasStore((s) => s.canvas?.nodes) as
    | MetricCard[]
    | undefined;

  const { config, series, rows, pie, hasData } = useMemo(
    () => resolveChartSeries(cards || [], seriesCardIds),
    [cards, seriesCardIds]
  );

  const TypeIcon = TYPE_ICON[chartType];

  const axisProps = {
    tickLine: false,
    axisLine: false,
    tick: { fontSize: 11 },
  } as const;

  const renderChart = () => {
    if (!hasData) {
      return (
        <div className="h-[200px] flex flex-col items-center justify-center gap-2 rounded-lg border border-dashed border-border bg-muted/30 text-center">
          <TypeIcon className="h-6 w-6 text-muted-foreground" />
          <p className="text-sm text-muted-foreground px-6">
            Connect a metric card to this node, or pick series in&nbsp;
            <Settings2 className="inline h-3.5 w-3.5 -mt-0.5" /> settings.
          </p>
        </div>
      );
    }

    if (chartType === 'pie') {
      return (
        <ChartContainer config={config} className="aspect-auto h-[200px] w-full">
          <PieChart>
            <ChartTooltip content={<ChartTooltipContent hideLabel />} />
            <Pie
              data={pie}
              dataKey="value"
              nameKey="label"
              innerRadius={45}
              outerRadius={78}
              paddingAngle={2}
              strokeWidth={2}
            >
              {pie.map((slice) => (
                <Cell key={slice.key} fill={slice.fill} />
              ))}
            </Pie>
            <ChartLegend
              content={(props) => (
                <ChartLegendContent {...(props as any)} nameKey="label" />
              )}
            />
          </PieChart>
        </ChartContainer>
      );
    }

    const grid = (
      <CartesianGrid vertical={false} strokeDasharray="3 3" opacity={0.4} />
    );
    const x = <XAxis dataKey="period" {...axisProps} minTickGap={16} />;
    const y = <YAxis {...axisProps} width={36} tickFormatter={formatCompact} />;
    const tooltip = <ChartTooltip content={<ChartTooltipContent />} />;
    const legend = showLegend ? (
      <ChartLegend content={(props) => <ChartLegendContent {...(props as any)} />} />
    ) : null;

    if (chartType === 'line') {
      return (
        <ChartContainer config={config} className="aspect-auto h-[200px] w-full">
          <LineChart data={rows} margin={{ left: 4, right: 8, top: 8 }}>
            {grid}
            {x}
            {y}
            {tooltip}
            {legend}
            {series.map((s) => (
              <Line
                key={s.key}
                type="monotone"
                dataKey={s.key}
                stroke={`var(--color-${s.key})`}
                strokeWidth={2}
                dot={false}
                activeDot={{ r: 4 }}
                connectNulls
              />
            ))}
          </LineChart>
        </ChartContainer>
      );
    }

    if (chartType === 'bar') {
      return (
        <ChartContainer config={config} className="aspect-auto h-[200px] w-full">
          <BarChart data={rows} margin={{ left: 4, right: 8, top: 8 }}>
            {grid}
            {x}
            {y}
            {tooltip}
            {legend}
            {series.map((s) => (
              <Bar
                key={s.key}
                dataKey={s.key}
                fill={`var(--color-${s.key})`}
                radius={[4, 4, 0, 0]}
              />
            ))}
          </BarChart>
        </ChartContainer>
      );
    }

    // area (default)
    return (
      <ChartContainer config={config} className="aspect-auto h-[200px] w-full">
        <AreaChart data={rows} margin={{ left: 4, right: 8, top: 8 }}>
          <defs>
            {series.map((s) => (
              <linearGradient
                key={s.key}
                id={`fill-${id}-${s.key}`}
                x1="0"
                y1="0"
                x2="0"
                y2="1"
              >
                <stop
                  offset="5%"
                  stopColor={`var(--color-${s.key})`}
                  stopOpacity={0.45}
                />
                <stop
                  offset="95%"
                  stopColor={`var(--color-${s.key})`}
                  stopOpacity={0.05}
                />
              </linearGradient>
            ))}
          </defs>
          {grid}
          {x}
          {y}
          {tooltip}
          {legend}
          {series.map((s) => (
            <Area
              key={s.key}
              type="monotone"
              dataKey={s.key}
              stroke={`var(--color-${s.key})`}
              strokeWidth={2}
              fill={`url(#fill-${id}-${s.key})`}
              connectNulls
              stackId={undefined}
            />
          ))}
        </AreaChart>
      </ChartContainer>
