              {isKpi ? 'Metric' : 'Metrics'}
              {selectedIds.length > 0 && (
                <span className="ml-1 text-xs text-muted-foreground">
                  ({selectedIds.length} selected)
                </span>
              )}
            </Label>
            <div className="max-h-64 space-y-1 overflow-auto rounded-md border border-border p-2">
